import{c as a,Q as i,j as n,m as t}from"./chunks/framework.Bhbi9jCp.js";const k=JSON.parse('{"title":"GDExtension 与 Rust/C++ 性能模块入门","description":"","frontmatter":{},"headers":[],"relativePath":"godotLearning/25-GDExtension与Rust-C-性能模块入门.md","filePath":"godotLearning/25-GDExtension与Rust-C-性能模块入门.md","lastUpdated":1780014601000}'),e={name:"godotLearning/25-GDExtension与Rust-C-性能模块入门.md"};function p(l,s,h,d,r,o){return i(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="gdextension-与-rust-c-性能模块入门" tabindex="-1">GDExtension 与 Rust/C++ 性能模块入门 <a class="header-anchor" href="#gdextension-与-rust-c-性能模块入门" aria-label="Permalink to &quot;GDExtension 与 Rust/C++ 性能模块入门&quot;">​</a></h1><p>GDExtension 不是让你用 Rust 或 C++ 重写整个游戏。它适合把已经定位清楚的纯算法热点挪到原生代码里。</p><blockquote><p>一句话先记住:<strong>跨语言有成本,只有大循环里做足够多工作才值得。</strong></p></blockquote><hr><h2 id="一、什么时候需要-gdextension" tabindex="-1">一、什么时候需要 GDExtension <a class="header-anchor" href="#一、什么时候需要-gdextension" aria-label="Permalink to &quot;一、什么时候需要 GDExtension&quot;">​</a></h2><p>适合:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>大规模程序化生成</span></span>
<span class="line"><span>逐像素图像处理</span></span>
<span class="line"><span>大量路径/几何计算</span></span>
<span class="line"><span>复杂战斗数值批量结算</span></span>
<span class="line"><span>压缩、解析、加密这类纯算法</span></span></code></pre></div><p>不适合:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>玩家移动控制</span></span>
<span class="line"><span>普通 UI</span></span>
<span class="line"><span>简单敌人 AI</span></span>
<span class="line"><span>场景流</span></span>
<span class="line"><span>经常改的玩法原型</span></span></code></pre></div><p>先用 GDScript 写清楚,用 profiler 确认热点,再下沉到 GDExtension。</p><hr><h2 id="二、边界怎么画" tabindex="-1">二、边界怎么画 <a class="header-anchor" href="#二、边界怎么画" aria-label="Permalink to &quot;二、边界怎么画&quot;">​</a></h2><p>好边界:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GDScript 准备 PackedFloat32Array / PackedInt32Array</span></span>
<span class="line"><span>Rust/C++ 一次性处理大量数据</span></span>
<span class="line"><span>GDScript 拿结果更新节点</span></span></code></pre></div><p>坏边界:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GDScript 每帧循环 10000 次</span></span>
<span class="line"><span>每次调用一次 Rust 函数</span></span>
<span class="line"><span>Rust 函数只算一个小值</span></span></code></pre></div><p>跨界调用本身有成本。要把循环放到原生侧内部。</p><hr><h2 id="三、gdextension-是什么" tabindex="-1">三、GDExtension 是什么 <a class="header-anchor" href="#三、gdextension-是什么" aria-label="Permalink to &quot;三、GDExtension 是什么&quot;">​</a></h2><p>它由两部分组成:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>动态库: .dll / .dylib / .so</span></span>
<span class="line"><span>描述文件: .gdextension</span></span></code></pre></div><p>Godot 启动时读取 <code>.gdextension</code>,加载对应动态库,注册里面的类。注册后,GDScript 就能像用普通类一样使用。</p><p>你不需要重编 Godot 引擎。这是它和 engine module 的主要区别。</p><hr><h2 id="四、一个适合下沉的例子" tabindex="-1">四、一个适合下沉的例子 <a class="header-anchor" href="#四、一个适合下沉的例子" aria-label="Permalink to &quot;四、一个适合下沉的例子&quot;">​</a></h2><p>比如程序化生成里有一段:</p><div class="language-gdscript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">gdscript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> height:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> width:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            value </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> expensive_noise</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x, y, i)</span></span></code></pre></div><p>地图 512x512,每格 8 层噪声,就是 200 多万次循环。GDScript 能跑,但 loading 会卡。</p><p>适合改成:</p><div class="language-gdscript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">gdscript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> heights: </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PackedFloat32Array</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> NativeTerrain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">generate_heightmap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(width, height, seed)</span></span></code></pre></div><p>原生侧一次性生成整张图,返回 packed array。GDScript 只负责把结果写进 TileMap 或 Image。</p><hr><h2 id="五、rust-工程心智" tabindex="-1">五、Rust 工程心智 <a class="header-anchor" href="#五、rust-工程心智" aria-label="Permalink to &quot;五、Rust 工程心智&quot;">​</a></h2><p>用 Rust 时,常见结构:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rust/</span></span>
<span class="line"><span>  Cargo.toml</span></span>
<span class="line"><span>  src/lib.rs</span></span>
<span class="line"><span>godot/</span></span>
<span class="line"><span>  native/terrain.gdextension</span></span>
<span class="line"><span>  native/libterrain.dylib</span></span></code></pre></div><p>Rust 类注册成 Godot 类,暴露方法。GDScript 只看到:</p><div class="language-gdscript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">gdscript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> terrain </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> NativeTerrain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">new</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> data </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> terrain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">generate_heightmap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">256</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">256</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">12345</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>这篇不展开 Rust 语法。重点是边界:传入简单值和 PackedArray,返回简单值和 PackedArray,少传 Node。</p><hr><h2 id="六、不要在原生侧乱碰节点树" tabindex="-1">六、不要在原生侧乱碰节点树 <a class="header-anchor" href="#六、不要在原生侧乱碰节点树" aria-label="Permalink to &quot;六、不要在原生侧乱碰节点树&quot;">​</a></h2><p>即使用 Rust/C++ 能拿到 <code>Node</code>,也不要把场景逻辑搬进去。</p><p>推荐:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原生侧: 纯计算</span></span>
<span class="line"><span>GDScript: 节点、信号、场景、UI</span></span></code></pre></div><p>原因:</p><ul><li>节点生命周期复杂。</li><li>调试成本高。</li><li>玩法迭代慢。</li><li>跨界调用太碎会抵消性能收益。</li></ul><hr><h2 id="七、发布要考虑平台" tabindex="-1">七、发布要考虑平台 <a class="header-anchor" href="#七、发布要考虑平台" aria-label="Permalink to &quot;七、发布要考虑平台&quot;">​</a></h2><p>每个平台要对应动态库:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Windows: .dll</span></span>
<span class="line"><span>macOS: .dylib</span></span>
<span class="line"><span>Linux: .so</span></span></code></pre></div><p>移动端、Web、主机平台还会更麻烦。你决定上 GDExtension 前,要先问:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个项目真的需要多平台导出吗?</span></span>
<span class="line"><span>每个平台的构建链能不能维护?</span></span>
<span class="line"><span>这个性能热点能不能先用 GDScript 优化掉?</span></span></code></pre></div><p>如果答案不清楚,先别上。</p><hr><h2 id="八、验收" tabindex="-1">八、验收 <a class="header-anchor" href="#八、验收" aria-label="Permalink to &quot;八、验收&quot;">​</a></h2><ul><li>已用 profiler 确认热点。</li><li>原生函数一次处理大数组,不是频繁小调用。</li><li>GDScript 仍负责场景树和玩法流程。</li><li>跨界数据用 PackedArray 或简单类型。</li><li>已考虑目标平台动态库构建。</li><li>有 GDScript 版本作为对照或 fallback。</li></ul><hr><h2 id="常见坑" tabindex="-1">常见坑 <a class="header-anchor" href="#常见坑" aria-label="Permalink to &quot;常见坑&quot;">​</a></h2><p><strong>坑 1:过早优化。</strong></p><p>原型期玩法还没定,先别把逻辑锁进原生库。</p><p><strong>坑 2:把 Node 传来传去。</strong></p><p>这会让原生层和场景树强耦合。传数据。</p><p><strong>坑 3:循环还留在 GDScript。</strong></p><p>每次只调用原生函数算一个点,收益很小。整批处理。</p><p><strong>坑 4:忘了发布成本。</strong></p><p>GDExtension 不是只有写代码,还有每个平台构建和打包。</p><hr><p>下一篇进入发布:多平台导出、D3D12 和增量补丁。</p>`,67)])])}const g=a(e,[["render",p]]);export{k as __pageData,g as default};
